import{_ as e,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"부록 | agent-app-factory","description":"참조 문서: CLI 명령어 전체 목록, 프로젝트 디렉토리 구조 상세 설명, 코드 스타일 요구사항 및 기술 스택 설명.","frontmatter":{"title":"부록 | agent-app-factory","sidebarTitle":"부록","subtitle":"부록","description":"참조 문서: CLI 명령어 전체 목록, 프로젝트 디렉토리 구조 상세 설명, 코드 스타일 요구사항 및 기술 스택 설명.","order":210},"headers":[],"relativePath":"ko/hyz1992/agent-app-factory/appendix/index.md","filePath":"ko/hyz1992/agent-app-factory/appendix/index.md"}'),o={name:"ko/hyz1992/agent-app-factory/appendix/index.md"};function c(l,a,d,n,s,h){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="부록" tabindex="-1">부록 <a class="header-anchor" href="#부록" aria-label="Permalink to &quot;부록&quot;">​</a></h1><p>이 장에는 참조 문서와 추가 자료가 포함되어 있어 AI App Factory의 기술적 세부사항을 더 깊이 이해할 수 있습니다.</p><h2 id="하위-페이지-내비게이션" tabindex="-1">하위 페이지 내비게이션 <a class="header-anchor" href="#하위-페이지-내비게이션" aria-label="Permalink to &quot;하위 페이지 내비게이션&quot;">​</a></h2><h3 id="cli-명령어-참조" tabindex="-1"><a href="./../cli-commands/">CLI 명령어 참조</a> <a class="header-anchor" href="#cli-명령어-참조" aria-label="Permalink to &quot;[CLI 명령어 참조](../cli-commands/)&quot;">​</a></h3><p>전체 CLI 명령어 목록, 매개변수 설명 및 사용 예제. <code>init</code>, <code>run</code>, <code>continue</code>, <code>status</code>, <code>list</code> 및 <code>reset</code> 등의 명령어 포함.</p><h3 id="디렉토리-구조-상세-설명" tabindex="-1"><a href="./../directory-structure/">디렉토리 구조 상세 설명</a> <a class="header-anchor" href="#디렉토리-구조-상세-설명" aria-label="Permalink to &quot;[디렉토리 구조 상세 설명](../directory-structure/)&quot;">​</a></h3><p>Factory 프로젝트의 완전한 디렉토리 구조와 각 파일의 용도 이해. <code>agents/</code>, <code>skills/</code>, <code>cli/</code> 등 핵심 디렉토리의 역할 포함.</p><h3 id="코드-스타일" tabindex="-1"><a href="./../code-standards/">코드 스타일</a> <a class="header-anchor" href="#코드-스타일" aria-label="Permalink to &quot;[코드 스타일](../code-standards/)&quot;">​</a></h3><p>생성된 코드가 따라야 할 TypeScript 코딩 스타일, 파일 구조, 주석 요구사항 및 커밋 메시지 스타일 이해.</p><h3 id="기술-스택-상세-설명" tabindex="-1"><a href="./../tech-stack/">기술 스택 상세 설명</a> <a class="header-anchor" href="#기술-스택-상세-설명" aria-label="Permalink to &quot;[기술 스택 상세 설명](../tech-stack/)&quot;">​</a></h3><p>생성된 애플리케이션에서 사용하는 기술 스택 이해: Node.js + Express + Prisma + React Native, 각 부분의 기술 선정 이유 포함.</p><h2 id="학습-경로-제안" tabindex="-1">학습 경로 제안 <a class="header-anchor" href="#학습-경로-제안" aria-label="Permalink to &quot;학습 경로 제안&quot;">​</a></h2><p>이 장의 문서는 <strong>참조 자료</strong>이므로 순서대로 읽을 필요가 없습니다. 주 튜토리얼을 학습하며 해당 장을 필요에 따라 참조하는 것이 좋습니다.</p><ul><li><a href="./../../start/installation/">설치 및 구성</a> 학습 시, <a href="./../cli-commands/">CLI 명령어 참조</a>를 참조할 수 있음</li><li><a href="./../../start/init-project/">Factory 프로젝트 초기화</a> 학습 시, <a href="./../directory-structure/">디렉토리 구조 상세 설명</a>를 참조할 수 있음</li><li>파이프라인 각 단계 학습 시, <a href="./../tech-stack/">기술 스택 상세 설명</a>를 참조할 수 있음</li><li>생성된 코드의 품질 기준을 이해하려면 <a href="./../code-standards/">코드 스타일</a>를 참조할 수 있음</li></ul><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><p>전제 요구사항 없음. 하지만 이 장의 내용을 더 잘 이해하려면 먼저 다음 튜토리얼을 완료하는 것이 좋습니다.</p><ul><li>✅ <a href="./../../start/getting-started/">빠른 시작: 아이디어에서 애플리케이션까지</a></li><li>✅ <a href="./../../start/installation/">설치 및 구성</a></li><li>✅ <a href="./../../start/init-project/">Factory 프로젝트 초기화</a></li></ul><h2 id="다음-단계-안내" tabindex="-1">다음 단계 안내 <a class="header-anchor" href="#다음-단계-안내" aria-label="Permalink to &quot;다음 단계 안내&quot;">​</a></h2><p>주 튜토리얼 학습을 완료한 후 계속 탐색할 수 있습니다.</p><ul><li><a href="./../../changelog/release-notes/">변경 로그</a>에서 최신 기능 확인</li><li><a href="./../../faq/best-practices/">모범 사례</a>를 검토하여 사용 효율 향상</li><li><a href="./../../advanced/">고급 주제</a>를 깊이 있게 학습하여 시스템 설계 원리 이해</li></ul>',20)])])}const u=e(o,[["render",c]]);export{f as __pageData,u as default};
